sql:
SELECT DISTINCT researchers.name, researchers.department
FROM researchers
JOIN simulations ON researchers.researcher_id = simulations.researcher_id;

SELECT simulation_id, COUNT(frame_id) AS total_frames
FROM simulation_frames
GROUP BY simulation_id;

SELECT DISTINCT simulation_id
FROM simulation_frames
WHERE delta_total > 0;

SELECT frame_id, LN(temperature) AS "Logarithmic Temperature", LN(pressure) AS "Logarithmic Pressure"
FROM simulation_frames
ORDER BY frame_id;

SELECT pressure, temperature, frame_number 
FROM simulation_frames 
WHERE simulation_id = 0;

SELECT COUNT(*) 
FROM simulation_frames 
WHERE frame_number > 5 AND frame_id > 20;

SELECT * 
FROM simulation_frames 
WHERE simulation_id = (SELECT simulation_id FROM simulations WHERE simulation_name = '<simulation_name>');

SELECT total_energy 
FROM energy_contributions 
WHERE frame_id = 1;

